mapper.select:
/** 통합청구 청구계정ID 조회 **/ SELECT BAN, CUSTOMER_ID, COL_DELINQ_STATUS, MARKET_GUBUN, BL_BILLING_METHOD, BANK_ACCT_HOLDER_ID, BAN_LINK_NAME, CONTRACT_NUM, EVNT_TRTM_DT FROM (SELECT A.BAN, A.CUSTOMER_ID, A.COL_DELINQ_STATUS, A.MARKET_GUBUN, A.BL_BILLING_METHOD, A.BANK_ACCT_HOLDER_ID, A.BAN_LINK_NAME, B.CONTRACT_NUM, A.EVNT_TRTM_DT FROM (SELECT BAN, CUSTOMER_ID, COL_DELINQ_STATUS, MARKET_GUBUN, BL_BILLING_METHOD, BL_SPCL_BAN_CODE, BANK_ACCT_HOLDER_ID, BAN_LINK_NAME, EVNT_TRTM_DT FROM MSP_JUO_BAN_INFO WHERE 1=1 AND BL_BILLING_METHOD != 'R' -- 지로 제외 AND COL_DELINQ_STATUS != 'D' -- 미납 제외 AND MARKET_GUBUN = 'KIS' -- 파라미터 : 청구계정ID AND BAN = #{ban} ) A INNER JOIN (SELECT CONTRACT_NUM, BAN, CUSTOMER_ID FROM MSP_JUO_BAN_MAPP_INFO WHERE (APP_END_DATE = '99991231000000' OR APP_END_DATE = '99991231235959') ) B ON B.BAN = A.BAN AND B.CUSTOMER_ID = A.CUSTOMER_ID INNER JOIN (SELECT CUSTOMER_ID, CUSTOMER_TYPE, CUSTOMER_SSN, DRIVR_LICNS_NO, TAX_ID, CUSTOMER_LINK_NAME, CUST_IDNT_NO_IND_CD FROM MSP_JUO_CUS_INFO WHERE 1=1
AND CUSTOMER_LINK_NAME = #{customerLinkName}
AND (CUSTOMER_SSN = CRYPTO_AES256.ENC_AES(#{customerSsn}) OR DRIVR_LICNS_NO = #{customerSsn} OR TAX_ID = #{customerSsn})
) C ON C.CUSTOMER_ID = B.CUSTOMER_ID ORDER BY A.EVNT_TRTM_DT DESC ) BAN WHERE ROWNUM = 1
